$(function(){
// Abrir modal de cupons
$('button.btn-ver-mais-cupons').click(function(){
$('#cupomModal').modal('show');
});
// Enviar cupons via e-mail
$('.cupons-via-email button').click(function(){
$('#cuponsViaEmail').modal('show');
});
// Impressão individual de cupom
btnUniquePrint = $('.to-unique-print');
btnUniquePrint.click(function(){
currentCoupom = $(this).data('cupom');
organizeCouponsModal(currentCoupom);
$(".modal-cupom").modal('show');
});
function organizeCouponsModal(currentCoupom) {
// Resetar Cupons Iniciais
getDefaultCouponsModal();
modalCupons = $(".modal-cupom");
contentCupons = $('.cupom-beneficio .cupom', modalCupons);
parentContentCupons = $('.cupom-beneficio .cupom', modalCupons).parent();
// Cupons iniciais clonados e manipulados
contentCupons.clone()
.removeClass('default-content')
.addClass('clone-content-cupons')
.appendTo(parentContentCupons);
contentCuponsClone = $('.cupom-beneficio .cupom.clone-content-cupons', modalCupons);
contentCuponsClone.removeClass('d-none');
$('h3', contentCuponsClone).remove();
$(''+currentCoupom+'
').appendTo(contentCuponsClone);
// Default Content
defaultContentCupons = $('.cupom-beneficio .cupom.default-content', modalCupons);
defaultContentCupons.addClass('d-none');
}
function getDefaultCouponsModal() {
modalCupons = $(".modal-cupom");
defaultContentCupons = $('.cupom-beneficio .cupom.default-content', modalCupons);
// Remove Clone Content Coupons
contentCuponsClone = $('.cupom-beneficio .cupom.clone-content-cupons', modalCupons);
contentCuponsClone.remove();
// Show Default Coupons
defaultContentCupons.removeClass('d-none');
}
});
